В QPainter нет специального класса или метода для создания изменяемого (resizeable) QRect. Однако, вы можете создать свой собственный класс, который будет хранить QRect и размер изменения, а затем обновлять координаты и размеры при изменении размера окна.

Примерно так можно реализовать resizeable QRect:

```cpp
class ResizeableRect {
public:
    ResizeableRect(QRect rect) : m_rect(rect) {}

    void resize(int dx, int dy) {
        m_rect.setWidth(m_rect.width() + dx);
        m_rect.setHeight(m_rect.height() + dy);
    }

    QRect rect() const {
        return m_rect;
    }

private:
    QRect m_rect;
};
```

Затем вы можете использовать этот класс в QPainter, например:

```cpp
void MyWidget::paintEvent(QPaintEvent *event) {
    QPainter painter(this);

    // Инициализируем ResizeableRect
    static ResizeableRect resizeableRect(QRect(50, 50, 100, 100));

    // Рисуем resizeableRect
    painter.drawRect(resizeableRect.rect());

    // При изменении размера окна вызываем resize у resizeableRect
    connect(this, &QWidget::resizeEvent, [&](QResizeEvent *resizeEvent) {
        int dx = resizeEvent->size().width() - resizeEvent->oldSize().width();
        int dy = resizeEvent->size().height() - resizeEvent->oldSize().height();
        resizeableRect.resize(dx, dy);
        update();
    });
}
```

Это простой пример и может потребоваться дополнительная работа, например, для обработки граничных условий или изменения других параметров.

Если вам нужно изменять размер прямоугольника напрямую, а не при изменении размера окна, вы можете использовать события мыши для отслеживания изменений размера и обновления прямоугольника. 

Ниже приведен пример реализации изменяемого QRect с использованием событий мыши:

```cpp
class ResizeableRect {
public:
    ResizeableRect(QRect rect) : m_rect(rect), m_resizeMode(None) {}

    enum ResizeMode {
        None,
        TopLeft,
        TopRight,
        BottomLeft,
        BottomRight
    };

    void mousePressEvent(QPoint pos) {
        // Определяем режим изменения размера
        if (m_rect.adjusted(3, 3, -3, -3).contains(pos)) {
            m_resizeMode = None;
            return;
        }

        if (m_rect.adjusted(3, 3, -3, -3).topLeft().contains(pos)) {
            m_resizeMode = TopLeft;
        } else if (m_rect.adjusted(3, 3, -3, -3).topRight().contains(pos)) {
            m_resizeMode = TopRight;
        } else if (m_rect.adjusted(3, 3, -3, -3).bottomLeft().contains(pos)) {
            m_resizeMode = BottomLeft;
        } else if (m_rect.adjusted(3, 3, -3, -3).bottomRight().contains(pos)) {
            m_resizeMode = BottomRight;
        }
    }

    void mouseMoveEvent(QPoint pos) {
        switch (m_resizeMode) {
            case TopLeft:
                m_rect.setTopLeft(pos);
                break;
            case TopRight:
                m_rect.setTopRight(pos);
                break;
            case BottomLeft:
                m_rect.setBottomLeft(pos);
                break;
            case BottomRight:
                m_rect.setBottomRight(pos);
                break;
            default:
                break;
        }
    }

    void mouseReleaseEvent() {
        m_resizeMode = None;
    }

    QRect rect() const {
        return m_rect;
    }

private:
    QRect m_rect;
    ResizeMode m_resizeMode;
};
```

Пример использования ResizeableRect в QWidget:

```cpp
void MyWidget::mousePressEvent(QMouseEvent *event) {
    m_resizeableRect.mousePressEvent(event->pos());
    update();
}

void MyWidget::mouseMoveEvent(QMouseEvent *event) {
    m_resizeableRect.mouseMoveEvent(event->pos());
    update();
}

void MyWidget::mouseReleaseEvent(QMouseEvent *event) {
    m_resizeableRect.mouseReleaseEvent();
    update();
}

void MyWidget::paintEvent(QPaintEvent *event) {
    QPainter painter(this);

    // Инициализируем ResizeableRect
    static ResizeableRect resizeableRect(QRect(50, 50, 100, 100));

    // Рисуем resizeableRect
    painter.drawRect(resizeableRect.rect());
}
```

В этом примере реализовано изменение размера прямоугольника при нажатии и перемещении мыши в указанных областях прямоугольника.

В PySide6 (Qt for Python) вы можете создать подобный resizeable QRect, используя аналогичный подход событий мыши. Ниже приведен пример кода, демонстрирующий, как реализовать изменяемый прямоугольник в PySide6:

```python
from PySide6.QtWidgets import QApplication, QGraphicsView, QGraphicsScene, QGraphicsRectItem
from PySide6.QtCore import QRectF, Qt
from PySide6.QtGui import QColor

class ResizeableRect(QGraphicsRectItem):
    def __init__(self, x, y, width, height):
        super().__init__(x, y, width, height)
        self.setPen(QColor(Qt.black))
        self.setFlag(QGraphicsItem.ItemIsMovable)

    def mousePressEvent(self, event):
        self.origin = self.rect().topLeft()
        self.resize_mode = None
        if self.rect().adjusted(3, 3, -3, -3).contains(event.pos()):
            self.resize_mode = 'None'
            return
        if self.rect().adjusted(3, 3, -3, -3).topLeft().contains(event.pos()):
            self.resize_mode = 'TopLeft'
        elif self.rect().adjusted(3, 3, -3, -3).topRight().contains(event.pos()):
            self.resize_mode = 'TopRight'
        elif self.rect().adjusted(3, 3, -3, -3).bottomLeft().contains(event.pos()):
            self.resize_mode = 'BottomLeft'
        elif self.rect().adjusted(3, 3, -3, -3).bottomRight().contains(event.pos()):
            self.resize_mode = 'BottomRight'

    def mouseMoveEvent(self, event):
        if self.resize_mode == 'TopLeft':
            self.setRect(QRectF(event.pos(), self.origin))
        elif self.resize_mode == 'TopRight':
            self.setRect(QRectF(self.origin, event.pos()))
        elif self.resize_mode == 'BottomLeft':
            self.setRect(QRectF(event.pos().x(), self.origin.y(), self.origin.x(), event.pos().y()))
        elif self.resize_mode == 'BottomRight':
            self.setRect(QRectF(self.origin, event.pos()))

class MainView(QGraphicsView):
    def __init__(self):
        super().__init__()
        scene = QGraphicsScene()
        self.setScene(scene)
        resizeable_rect = ResizeableRect(50, 50, 100, 100)
        scene.addItem(resizeable_rect)

if __name__ == "__main__":
    app = QApplication([])
    view = MainView()
    view.show()
    app.exec()
```

Этот код создает окно с изменяемым прямоугольником, который можно перемещать и изменять размер с использованием мыши. При нажатии на прямоугольник и перемещении мыши на углах и сторонах прямоугольника можно изменить его размер.
